type RetryConfig = {
  maxAttempts: number;
  baseDelayMs: number;
};

export type TinybirdClientConfig = {
  apiUrl: string;
  token: string;
  datasource: string;
  fetch?: typeof fetch;
  retry?: RetryConfig;
  wait?: boolean;
};

export type TinybirdClient = {
  appendEvents: (events: unknown[]) => Promise<void>;
};

function readRequiredEnv(name: string): string {
  const value = process.env[name];
  if (typeof value === "string" && value.length > 0) return value;
  throw new Error(`Missing required environment variable: ${name}`);
}

function buildEventsUrl(apiUrl: string, datasource: string, wait: boolean): string {
  const url = new URL("/v0/events", apiUrl);
  url.searchParams.set("name", datasource);
  url.searchParams.set("wait", wait ? "true" : "false");
  return url.toString();
}

function toNdjson(events: unknown[]): string {
  return `${events.map((e) => JSON.stringify(e)).join("\n")}\n`;
}

function isRetriableStatus(status: number): boolean {
  return status === 408 || status === 429 || status >= 500;
}

async function sleep(ms: number): Promise<void> {
  if (ms <= 0) return;
  await new Promise((resolve) => setTimeout(resolve, ms));
}

export function createTinybirdClientFromEnv(): TinybirdClient {
  return createTinybirdClient({
    apiUrl: readRequiredEnv("TINYBIRD_API_URL"),
    token: readRequiredEnv("TINYBIRD_EVENTS_TOKEN"),
    datasource: "events",
  });
}

export function createTinybirdClient(config: TinybirdClientConfig): TinybirdClient {
  const fetchImpl = config.fetch ?? fetch;
  const retry: RetryConfig = config.retry ?? { maxAttempts: 3, baseDelayMs: 200 };
  const wait = config.wait ?? true;

  if (!config.apiUrl) throw new Error("Missing Tinybird apiUrl");
  if (!config.token) throw new Error("Missing Tinybird token");
  if (!config.datasource) throw new Error("Missing Tinybird datasource");

  const url = buildEventsUrl(config.apiUrl, config.datasource, wait);

  return {
    async appendEvents(events: unknown[]) {
      if (!Array.isArray(events) || events.length === 0) return;

      const body = toNdjson(events);
      let lastError: unknown;

      for (let attempt = 0; attempt < retry.maxAttempts; attempt++) {
        try {
          const response = await fetchImpl(url, {
            method: "POST",
            headers: {
              Authorization: `Bearer ${config.token}`,
              "Content-Type": "application/x-ndjson",
            },
            body,
          });

          if (response.ok) return;

          const responseText = await response.text().catch(() => "");
          const error = new Error(
            `Tinybird ingestion failed (status=${response.status}): ${responseText || response.statusText}`,
          );

          if (!isRetriableStatus(response.status) || attempt === retry.maxAttempts - 1) {
            throw error;
          }

          lastError = error;
        } catch (error) {
          if (attempt === retry.maxAttempts - 1) throw error;
          lastError = error;
        }

        const delay = retry.baseDelayMs * Math.pow(2, attempt);
        await sleep(delay);
      }

      throw lastError instanceof Error ? lastError : new Error("Tinybird ingestion failed");
    },
  };
}

"use client";

import React, { useEffect, useMemo, useState } from "react";

import OnboardingChecklist from "../../../../components/dashboard/onboarding-checklist";
import QuotaDisplay from "../../../../components/dashboard/quota-display";
import Skeleton, { SkeletonList } from "../../../../components/dashboard/skeleton";
import StatusBadge from "../../../../components/dashboard/status-badge";
import { useProject } from "../../../../lib/hooks/use-project";
import type { UserPlan } from "../../../../lib/stripe/plans";

type RegenerateState = {
  status: "idle" | "loading" | "success" | "error";
  message: string;
  retryAfter?: number;
};

function canRegenerateByStatus(status: string): boolean {
  return status === "analysis_failed" || status === "pr_closed" || status === "unsupported";
}

function shouldShowQuota(status: string): boolean {
  return status === "pr_pending" || status === "active";
}

type StatusCardConfig = {
  title: string;
  description: string;
  bgClass: string;
  borderClass: string;
  iconClass: string;
};

const STATUS_CARD_CONFIG: Record<string, StatusCardConfig> = {
  unsupported: {
    title: "Repository Not Supported",
    description:
      "This repository may use an unsupported framework or structure. Click 'Re-run Analysis' to try again after making changes to your repository.",
    bgClass: "bg-amber-50",
    borderClass: "border-amber-200",
    iconClass: "text-amber-500",
  },
  analysis_failed: {
    title: "Analysis Failed",
    description:
      "Something went wrong during analysis. This could be a temporary issue. Click 'Re-run Analysis' to try again.",
    bgClass: "bg-red-50",
    borderClass: "border-red-200",
    iconClass: "text-red-500",
  },
  pr_closed: {
    title: "Pull Request Closed",
    description:
      "The analytics PR was closed without merging. Click 'Re-run Analysis' to generate a new PR.",
    bgClass: "bg-slate-50",
    borderClass: "border-slate-200",
    iconClass: "text-slate-400",
  },
};

function StatusCard({ status }: { status: string }) {
  const config = STATUS_CARD_CONFIG[status];
  if (!config) return null;

  return (
    <div className={`rounded-lg border ${config.borderClass} ${config.bgClass} p-4`}>
      <div className="flex items-start gap-3">
        <div className={`mt-0.5 ${config.iconClass}`}>
          <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
            <path
              d="M10 6v4m0 4h.01M19 10a9 9 0 11-18 0 9 9 0 0118 0z"
              stroke="currentColor"
              strokeWidth="1.5"
              strokeLinecap="round"
              strokeLinejoin="round"
            />
          </svg>
        </div>
        <div>
          <h3 className="text-sm font-semibold text-warm-900">{config.title}</h3>
          <p className="mt-1 text-sm text-warm-600">{config.description}</p>
        </div>
      </div>
    </div>
  );
}

function ExternalLinkIcon() {
  return (
    <svg width="14" height="14" viewBox="0 0 16 16" fill="none" className="inline-block">
      <path
        d="M12 8.667V12.667C12 13.0203 11.8595 13.3594 11.6095 13.6095C11.3594 13.8595 11.0203 14 10.667 14H3.333C2.97971 14 2.64057 13.8595 2.39052 13.6095C2.14048 13.3594 2 13.0203 2 12.667V5.333C2 4.97971 2.14048 4.64057 2.39052 4.39052C2.64057 4.14048 2.97971 4 3.333 4H7.333"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
      <path d="M10 2H14V6" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
      <path d="M6.667 9.333L14 2" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}

function getCanRegenerateAction(project: Record<string, unknown> | null, status: string): boolean {
  const actions = project?.actions;
  if (actions && typeof actions === "object" && "canRegenerate" in actions) {
    return Boolean((actions as { canRegenerate?: unknown }).canRegenerate);
  }

  return canRegenerateByStatus(status);
}

export default function ProjectDetailPage({ params }: { params: { id: string } }) {
  const projectId = params.id;
  const projectQuery = useProject(projectId);

  const [regenerateState, setRegenerateState] = useState<RegenerateState>({ status: "idle", message: "" });
  const [optimisticStatus, setOptimisticStatus] = useState<string | null>(null);
  const [retryCountdown, setRetryCountdown] = useState<number>(0);

  const project = useMemo(() => {
    const data = projectQuery.data as null | { project?: unknown };
    return (data?.project as null | Record<string, unknown>) ?? null;
  }, [projectQuery.data]);

  const userPlan: UserPlan = useMemo(() => {
    const plan = (projectQuery.data as null | Record<string, unknown>)?.userPlan;
    return plan === "free" || plan === "pro" || plan === "team" ? plan : "pro";
  }, [projectQuery.data]);

  // Auto-dismiss success message after 5 seconds
  useEffect(() => {
    if (regenerateState.status === "success") {
      const timer = setTimeout(() => {
        setRegenerateState({ status: "idle", message: "" });
      }, 5000);
      return () => clearTimeout(timer);
    }
  }, [regenerateState.status]);

  // Rate limit countdown timer
  useEffect(() => {
    if (retryCountdown > 0) {
      const timer = setTimeout(() => {
        setRetryCountdown((prev) => prev - 1);
      }, 1000);
      return () => clearTimeout(timer);
    } else if (retryCountdown === 0 && regenerateState.status === "error" && regenerateState.retryAfter) {
      setRegenerateState({ status: "idle", message: "" });
    }
  }, [retryCountdown, regenerateState.status, regenerateState.retryAfter]);

  // Clear optimistic status when real status updates to analyzing
  useEffect(() => {
    const realStatus = String(project?.status ?? "");
    if (realStatus === "analyzing" && optimisticStatus === "analyzing") {
      setOptimisticStatus(null);
    }
  }, [project?.status, optimisticStatus]);

  async function onRegenerate() {
    setRegenerateState({ status: "loading", message: "" });
    setOptimisticStatus("analyzing");

    try {
      const response = await fetch(`/api/projects/${encodeURIComponent(projectId)}/regenerate`, { method: "POST" });
      const body = (await response.json().catch(() => null)) as null | { success?: boolean; message?: string };

      if (!response.ok || !body?.success) {
        setOptimisticStatus(null);

        if (response.status === 429) {
          const retrySeconds = 300; // 5 minutes
          setRetryCountdown(retrySeconds);
          setRegenerateState({
            status: "error",
            message: `Rate limited. Try again in ${Math.ceil(retrySeconds / 60)} minutes.`,
            retryAfter: retrySeconds,
          });
        } else {
          setRegenerateState({ status: "error", message: body?.message ?? "Unable to regenerate." });
        }
        return;
      }

      setRegenerateState({
        status: "success",
        message: "Analysis started — this page will update automatically.",
      });
      await projectQuery.refetch();
    } catch {
      setOptimisticStatus(null);
      setRegenerateState({ status: "error", message: "Unable to regenerate." });
    }
  }

  if (projectQuery.isPending) {
    return (
      <div className="flex flex-col gap-6">
        <div className="rounded-lg border border-slate-200 bg-white p-4 shadow-sm">
          <Skeleton className="h-4 w-20" />
          <div className="mt-3 flex items-center justify-between gap-4">
            <Skeleton className="h-4 w-24" />
            <Skeleton className="h-4 w-16" />
          </div>
          <Skeleton className="mt-3 h-2 w-full" />
        </div>
        <SkeletonList />
      </div>
    );
  }

  if (projectQuery.isError) {
    return (
      <div className="rounded-lg border border-red-200 bg-red-50 p-4">
        <p className="text-sm text-red-700">Unable to load project. Please try again.</p>
      </div>
    );
  }

  const realStatus = String(project?.status ?? "");
  const displayStatus = optimisticStatus ?? realStatus;
  const prUrl = typeof project?.prUrl === "string" ? (project.prUrl as string) : null;
  const lastEventAt = typeof project?.lastEventAt === "string" ? (project.lastEventAt as string) : null;
  const quotaLimit = Number((projectQuery.data as Record<string, unknown>)?.quotaLimit ?? 0);
  const quotaUsed = Number((projectQuery.data as Record<string, unknown>)?.quotaUsed ?? 0);
  const isOverQuota = Boolean((projectQuery.data as Record<string, unknown>)?.isOverQuota);
  const canRegenerate = getCanRegenerateAction(project, realStatus);
  const isWaitingForFirstEvent = displayStatus === "active" && lastEventAt === null;

  const showRerunButton = canRegenerate && !optimisticStatus;
  const isRateLimited = retryCountdown > 0;

  return (
    <div className="flex flex-col gap-6">
      {/* Status Badge with optimistic update */}
      {optimisticStatus && (
        <div className="flex items-center gap-2">
          <StatusBadge status={displayStatus} />
          <span className="text-sm text-warm-500">Updating...</span>
        </div>
      )}

      {/* Status-specific empty state card */}
      {!optimisticStatus && canRegenerate && <StatusCard status={realStatus} />}

      {isWaitingForFirstEvent && (
        <div className="rounded-lg border border-sky-200 bg-sky-50 p-4">
          <p className="text-sm font-medium text-sky-900">
            Waiting for first event. Tally is installed, but no production events have been received yet.
          </p>
        </div>
      )}

      {/* Quick Actions */}
      <div className="flex flex-wrap items-center gap-3">
        {prUrl && (
          <a
            href={prUrl}
            target="_blank"
            rel="noreferrer"
            className="inline-flex items-center gap-1.5 rounded-md border border-slate-200 bg-white px-3 py-2 text-sm font-medium text-slate-700 shadow-sm transition-colors hover:bg-slate-50"
          >
            View PR <ExternalLinkIcon />
          </a>
        )}

        {showRerunButton && (
          <button
            type="button"
            onClick={onRegenerate}
            disabled={regenerateState.status === "loading" || isRateLimited}
            className="inline-flex items-center gap-1.5 rounded-md bg-slate-900 px-3 py-2 text-sm font-medium text-white shadow-sm transition-colors hover:bg-slate-800 disabled:opacity-50"
          >
            {regenerateState.status === "loading" ? "Re-running…" : "Re-run Analysis"}
          </button>
        )}
      </div>

      {/* Feedback messages */}
      {regenerateState.message && (
        <div
          className={[
            "rounded-md border px-3 py-2 text-sm flex items-center justify-between",
            regenerateState.status === "error"
              ? "border-red-200 bg-red-50 text-red-700"
              : "border-emerald-200 bg-emerald-50 text-emerald-700",
          ].join(" ")}
        >
          <span>{regenerateState.message}</span>
          {isRateLimited && (
            <span className="ml-2 font-mono text-xs">
              {Math.floor(retryCountdown / 60)}:{String(retryCountdown % 60).padStart(2, "0")}
            </span>
          )}
        </div>
      )}

      {/* QuotaDisplay only for relevant states */}
      {shouldShowQuota(displayStatus) && (
        <QuotaDisplay used={quotaUsed} limit={quotaLimit} isOverQuota={isOverQuota} userPlan={userPlan} />
      )}

      {/* OnboardingChecklist only when PR exists and not active */}
      {displayStatus !== "active" && prUrl && <OnboardingChecklist project={{ status: displayStatus, prUrl, lastEventAt }} />}
    </div>
  );
}

import { and, eq, gt } from "drizzle-orm";
import { cookies } from "next/headers";
import React from "react";

import { SESSION_COOKIE_NAME } from "../../../lib/auth/cookies";
import { db } from "../../../lib/db/client";
import { sessions, users } from "../../../lib/db/schema";
import { StripeReconcileClient } from "./stripe-reconcile-client";

export default async function SettingsPage() {
  const sessionId = cookies().get(SESSION_COOKIE_NAME)?.value ?? null;
  if (!sessionId) {
    return <p className="text-sm text-warm-700">Unauthorized.</p>;
  }

  const now = new Date();
  const sessionRows = await db
    .select({ userId: sessions.userId })
    .from(sessions)
    .where(and(eq(sessions.id, sessionId), gt(sessions.expiresAt, now)));

  const userId = sessionRows[0]?.userId ?? null;
  if (!userId) {
    return <p className="text-sm text-warm-700">Unauthorized.</p>;
  }

  const userRows = await db
    .select({
      email: users.email,
      plan: users.plan,
      stripeSubscriptionStatus: users.stripeSubscriptionStatus,
      stripeCancelAtPeriodEnd: users.stripeCancelAtPeriodEnd,
      stripeCurrentPeriodEnd: users.stripeCurrentPeriodEnd,
    })
    .from(users)
    .where(eq(users.id, userId));
  const user = userRows[0];
  if (!user) return <p className="text-sm text-warm-700">Unauthorized.</p>;

  return (
    <div className="flex w-full flex-col gap-6">
      <header className="flex flex-col gap-2 opacity-0 animate-fade-in">
        <h1 className="font-display text-2xl font-semibold tracking-tight text-warm-900">Account settings</h1>
        <p className="text-sm text-warm-500">Manage your account.</p>
      </header>

      <section className="rounded-lg border border-warm-200 bg-white p-4 shadow-warm opacity-0 animate-fade-in stagger-1">
        <StripeReconcileClient />
        <dl className="grid gap-3 text-sm">
          <div className="flex items-center justify-between gap-4">
            <dt className="text-warm-500">Email</dt>
            <dd className="font-medium text-warm-900">{user.email}</dd>
          </div>
          <div className="flex items-center justify-between gap-4">
            <dt className="text-warm-500">Plan</dt>
            <dd className="font-medium text-warm-900">{user.plan.charAt(0).toUpperCase() + user.plan.slice(1)}</dd>
          </div>
          {user.stripeSubscriptionStatus ? (
            <div className="flex items-center justify-between gap-4">
              <dt className="text-warm-500">Billing status</dt>
              <dd className="font-medium text-warm-900">
                {user.stripeSubscriptionStatus.charAt(0).toUpperCase() + user.stripeSubscriptionStatus.slice(1)}
              </dd>
            </div>
          ) : null}
          {user.stripeCurrentPeriodEnd ? (
            <div className="flex items-center justify-between gap-4">
              <dt className="text-warm-500">Current period end</dt>
              <dd className="font-medium text-warm-900">{user.stripeCurrentPeriodEnd.toISOString().slice(0, 10)}</dd>
            </div>
          ) : null}
          {typeof user.stripeCancelAtPeriodEnd === "boolean" ? (
            <div className="flex items-center justify-between gap-4">
              <dt className="text-warm-500">Cancel at period end</dt>
              <dd className="font-medium text-warm-900">{user.stripeCancelAtPeriodEnd ? "Yes" : "No"}</dd>
            </div>
          ) : null}
        </dl>
      </section>

      <section className="rounded-lg border border-warm-200 bg-white p-4 shadow-warm opacity-0 animate-fade-in stagger-2">
        <h2 className="font-display text-sm font-semibold text-warm-900">Billing</h2>
        <p className="mt-1 text-sm text-warm-500">Upgrade, downgrade, or manage your subscription.</p>

        <div className="mt-4 flex flex-wrap items-center gap-3">
          {user.plan === "free" ? (
            <>
              <form action="/api/stripe/checkout" method="post">
                <input type="hidden" name="plan" value="pro" />
                <button type="submit" className="group flex items-center gap-2 rounded-lg bg-brand-500 px-4 py-2 text-sm font-medium text-white shadow-warm transition-all hover:bg-brand-600 hover:shadow-warm-md active:scale-[0.98]">
                  Upgrade to Pro
                  <svg className="size-4 transition-transform group-hover:translate-x-0.5" viewBox="0 0 16 16" fill="none">
                    <path d="M3 8h10M9 4l4 4-4 4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                  </svg>
                </button>
              </form>
              <form action="/api/stripe/checkout" method="post">
                <input type="hidden" name="plan" value="team" />
                <button type="submit" className="group flex items-center gap-2 rounded-lg border border-warm-200 bg-white px-4 py-2 text-sm font-medium text-warm-900 shadow-warm transition-all hover:border-warm-300 hover:bg-warm-50 hover:shadow-warm-md active:scale-[0.98]">
                  Upgrade to Team
                  <svg className="size-4 transition-transform group-hover:translate-x-0.5" viewBox="0 0 16 16" fill="none">
                    <path d="M3 8h10M9 4l4 4-4 4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                  </svg>
                </button>
              </form>
            </>
          ) : (
            <form action="/api/stripe/portal" method="post">
              <button type="submit" className="group flex items-center gap-2 rounded-lg bg-brand-500 px-4 py-2 text-sm font-medium text-white shadow-warm transition-all hover:bg-brand-600 hover:shadow-warm-md active:scale-[0.98]">
                Manage billing
                <svg className="size-4 transition-transform group-hover:translate-x-0.5" viewBox="0 0 16 16" fill="none">
                  <path d="M3 8h10M9 4l4 4-4 4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
              </button>
            </form>
          )}
        </div>
      </section>
    </div>
  );
}

import { validateSession } from "../../../../lib/auth/session";
import { getUserById } from "../../../../lib/db/queries/users";
import { createAuthorizationCode } from "../../../../lib/oauth/codes";
import { getOAuthClient } from "../../../../lib/oauth/clients";
import { mcpResourceUrl } from "../../../../lib/oauth/metadata";
import {
  assertValidPkce,
  isRedirectUriRegistered,
  normalizeOAuthScope,
  validateResourceUrl,
} from "../../../../lib/oauth/validation";

function redirectWithParams(redirectUri: string, params: Record<string, string>): Response {
  const url = new URL(redirectUri);
  for (const [key, value] of Object.entries(params)) {
    url.searchParams.set(key, value);
  }
  return Response.redirect(url.toString(), 302);
}

function authorizeReturnPath(requestUrl: URL): string {
  return `${requestUrl.pathname}${requestUrl.search}`;
}

const LOCALHOSTS = new Set(["localhost", "127.0.0.1", "::1"]);

function hostnameFromHostHeader(hostHeader: string | null): string | null {
  if (!hostHeader) return null;

  try {
    return new URL(`http://${hostHeader}`).hostname.replace(/^\[|\]$/g, "");
  } catch {
    return null;
  }
}

async function resolveE2EAutoAuthorizeUserId(request: Request): Promise<
  | { status: "disabled" }
  | { status: "forbidden"; reason: string }
  | { status: "authorized"; userId: string }
> {
  if (process.env.E2E_TEST_MODE !== "1") return { status: "disabled" };
  if (process.env.NODE_ENV === "production") return { status: "forbidden", reason: "production" };

  const hostname = hostnameFromHostHeader(request.headers.get("host"));
  if (!hostname || !LOCALHOSTS.has(hostname)) {
    return { status: "forbidden", reason: "non_localhost_host" };
  }

  const userId = process.env.E2E_MCP_AUTH_USER_ID;
  if (!userId) return { status: "forbidden", reason: "missing_user_id" };

  try {
    const user = await getUserById(userId);
    if (!user) return { status: "forbidden", reason: "unknown_user_id" };
  } catch {
    return { status: "forbidden", reason: "user_lookup_failed" };
  }

  return { status: "authorized", userId };
}

function e2eForbidden(reason: string): Response {
  console.warn("MCP OAuth E2E auto-authorize blocked", { reason });
  return Response.json({ error: "e2e_auto_authorize_forbidden" }, { status: 403 });
}

async function createCodeRedirect(params: {
  clientId: string;
  userId: string;
  redirectUri: string;
  codeChallenge: string;
  codeChallengeMethod: string;
  scope: string;
  resource: string;
  state: string;
}): Promise<Response> {
  const authorizationCode = await createAuthorizationCode({
    clientId: params.clientId,
    userId: params.userId,
    redirectUri: params.redirectUri,
    codeChallenge: params.codeChallenge,
    codeChallengeMethod: params.codeChallengeMethod,
    scope: params.scope,
    resource: params.resource,
  });

  return redirectWithParams(params.redirectUri, { code: authorizationCode.code, state: params.state });
}

export async function GET(request: Request): Promise<Response> {
  const url = new URL(request.url);
  const clientId = url.searchParams.get("client_id") ?? "";
  const redirectUri = url.searchParams.get("redirect_uri") ?? "";
  const responseType = url.searchParams.get("response_type") ?? "";
  const state = url.searchParams.get("state") ?? "";
  const resource = url.searchParams.get("resource") ?? "";
  const codeChallenge = url.searchParams.get("code_challenge") ?? "";
  const codeChallengeMethod = url.searchParams.get("code_challenge_method") ?? "";

  const client = clientId ? await getOAuthClient(clientId) : null;
  if (!client || !redirectUri || !isRedirectUriRegistered({ redirectUri, registeredRedirectUris: client.redirectUris })) {
    return Response.json({ error: "invalid_client" }, { status: 400 });
  }

  if (responseType !== "code") {
    return redirectWithParams(redirectUri, { error: "unsupported_response_type", state });
  }

  let scope: string;
  let normalizedResource: string;
  try {
    scope = normalizeOAuthScope(url.searchParams.get("scope"));
    normalizedResource = validateResourceUrl(resource || mcpResourceUrl());
    assertValidPkce({ codeChallenge, codeChallengeMethod });
  } catch (error) {
    return redirectWithParams(redirectUri, {
      error: "invalid_request",
      error_description: error instanceof Error ? error.message : "Invalid authorization request",
      state,
    });
  }

  const e2eAutoAuthorize = await resolveE2EAutoAuthorizeUserId(request);
  if (e2eAutoAuthorize.status === "forbidden") {
    return e2eForbidden(e2eAutoAuthorize.reason);
  }
  if (e2eAutoAuthorize.status === "authorized") {
    return createCodeRedirect({
      clientId,
      userId: e2eAutoAuthorize.userId,
      redirectUri,
      codeChallenge,
      codeChallengeMethod,
      scope,
      resource: normalizedResource,
      state,
    });
  }

  const session = await validateSession(request);
  if (!session) {
    const loginUrl = new URL("/api/auth/github", url.origin);
    loginUrl.searchParams.set("return_to", authorizeReturnPath(url));
    return Response.redirect(loginUrl.toString(), 302);
  }

  return createCodeRedirect({
    clientId,
    userId: session.userId,
    redirectUri,
    codeChallenge,
    codeChallengeMethod,
    scope,
    resource: normalizedResource,
    state,
  });
}

import { consumeAuthorizationCode } from "../../../../lib/oauth/codes";
import { createOAuthTokenPair, rotateRefreshToken } from "../../../../lib/oauth/tokens";

function oauthError(error: string, status = 400, description?: string): Response {
  return Response.json({ error, error_description: description }, { status });
}

function tokenResponse(pair: {
  accessToken: string;
  refreshToken: string;
  tokenType: "Bearer";
  expiresIn: number;
  scope: string;
}): Response {
  return Response.json({
    access_token: pair.accessToken,
    token_type: pair.tokenType,
    expires_in: pair.expiresIn,
    scope: pair.scope,
    refresh_token: pair.refreshToken,
  });
}

export async function POST(request: Request): Promise<Response> {
  const form = await request.formData();
  const grantType = String(form.get("grant_type") ?? "");
  const clientId = String(form.get("client_id") ?? "");

  if (!clientId) return oauthError("invalid_client", 401);

  if (grantType === "authorization_code") {
    const code = String(form.get("code") ?? "");
    const redirectUri = String(form.get("redirect_uri") ?? "");
    const codeVerifier = String(form.get("code_verifier") ?? "");
    if (!code || !redirectUri || !codeVerifier) return oauthError("invalid_request");

    const consumed = await consumeAuthorizationCode({ code, clientId, redirectUri, codeVerifier });
    if (!consumed) return oauthError("invalid_grant");

    const resource = String(form.get("resource") ?? consumed.resource);
    if (resource !== consumed.resource) return oauthError("invalid_target");

    const pair = await createOAuthTokenPair({
      clientId,
      userId: consumed.userId,
      scope: consumed.scope,
      resource: consumed.resource,
    });

    return tokenResponse(pair);
  }

  if (grantType === "refresh_token") {
    const refreshToken = String(form.get("refresh_token") ?? "");
    if (!refreshToken) return oauthError("invalid_request");

    const pair = await rotateRefreshToken({ refreshToken, clientId });
    if (!pair) return oauthError("invalid_grant");
    return tokenResponse(pair);
  }

  return oauthError("unsupported_grant_type");
}

import { getUserFromRequest } from '../../../../../../lib/auth/get-user';
import {
  getLiveEvents,
  isLiveEventsSuccess,
  toDashboardLiveEventsResponse,
} from '../../../../../../lib/analytics/service';

function clamp(n: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, n));
}

export async function GET(
  request: Request,
  context: { params: Promise<{ id: string }> | { id: string } }
): Promise<Response> {
  const user = await getUserFromRequest(request);
  if (!user) return Response.json({ error: 'Unauthorized' }, { status: 401 });

  const params = 'then' in context.params ? await context.params : context.params;
  const projectId = params.id;
  if (!projectId) return Response.json({ error: 'Missing project id' }, { status: 400 });

  const url = new URL(request.url);
  const limitRaw = url.searchParams.get('limit');
  const limit = clamp(Number.parseInt(limitRaw ?? '20', 10) || 20, 1, 100);
  const sinceRaw = url.searchParams.get('since') ?? '';
  const parsedSince = sinceRaw ? new Date(sinceRaw) : null;
  const since = parsedSince && !Number.isNaN(parsedSince.getTime()) ? parsedSince : null;

  const result = await getLiveEvents({ userId: user.id, projectId, limit, since });
  if (result.status === 'project_not_found') {
    return Response.json({ error: 'Project not found' }, { status: 404 });
  }
  if (!isLiveEventsSuccess(result)) {
    return Response.json({ error: 'Analytics service unavailable' }, { status: 500 });
  }

  return Response.json(toDashboardLiveEventsResponse(result), { status: 200 });
}

