import { getPriceIdForPlan } from "../../../../lib/stripe/constants";
import { getStripe } from "../../../../lib/stripe/client";
import { isPaidPlan, type PaidPlan } from "../../../../lib/stripe/plans";

const ACTIVE_SUBSCRIPTION_STATUSES = new Set(["active", "trialing", "past_due", "unpaid"]);

function normalizeBaseUrl(url: string): string {
  return url.endsWith("/") ? url.slice(0, -1) : url;
}

async function createBillingPortalUrl(stripeCustomerId: string): Promise<string | null> {
  const stripe = getStripe();
  const appUrl = normalizeBaseUrl(getAppUrl());

  const portalSession = await stripe.billingPortal.sessions.create({
    customer: stripeCustomerId,
    return_url: `${appUrl}/settings`,
    configuration: process.env.STRIPE_BILLING_PORTAL_CONFIG_ID || undefined,
  });

  return typeof portalSession.url === "string" && portalSession.url.length > 0 ? portalSession.url : null;
}

export async function POST(request: Request): Promise<Response> {
  const session = await validateSession(request);
  if (!session) {
    return Response.json({ error: "Unauthorized" }, { status: 401 });
  }

  let formData: FormData;
  try {
    formData = await request.formData();
  } catch {
    return Response.json({ error: "Invalid request" }, { status: 400 });
  }

  const planRaw = formData.get("plan");
  if (!isPaidPlan(planRaw)) {
    return Response.json({ error: "Invalid plan" }, { status: 400 });
  }
  const plan: PaidPlan = planRaw;

  const rows = await db
    .select({ id: users.id, email: users.email, plan: users.plan, stripeCustomerId: users.stripeCustomerId })
    .from(users)
    .where(eq(users.id, session.userId));

  const user = rows[0];
  if (!user) {
    return Response.json({ error: "User not found" }, { status: 404 });
  }

  const stripe = getStripe();

  let stripeCustomerId = user.stripeCustomerId ?? null;
  if (!stripeCustomerId) {
    try {
      const customer = await stripe.customers.create({ email: user.email, metadata: { userId: user.id } });
      stripeCustomerId = customer.id;

      await db.update(users).set({ stripeCustomerId }).where(eq(users.id, user.id));
    } catch (error) {
      console.error("stripe.checkout.customer_create_failed", { userId: user.id, error });
      return Response.json({ error: "Failed to start checkout" }, { status: 500 });
    }
  }

  try {
    const subscriptions = await stripe.subscriptions.list({ customer: stripeCustomerId, status: "all", limit: 10 });
    const hasActiveSubscription = subscriptions.data.some((subscription) =>
      ACTIVE_SUBSCRIPTION_STATUSES.has(subscription.status),
    );

    if (hasActiveSubscription) {
      const manageUrl = await createBillingPortalUrl(stripeCustomerId);
      return Response.json({ error: "Subscription already exists", manageUrl }, { status: 409 });
    }
  } catch (error) {
    console.error("stripe.checkout.subscription_check_failed", { userId: user.id, stripeCustomerId, error });
    return Response.json({ error: "Failed to start checkout" }, { status: 500 });
  }

  const appUrl = normalizeBaseUrl(getAppUrl());

  try {
    const checkoutSession = await stripe.checkout.sessions.create({
      mode: "subscription",
      customer: stripeCustomerId,
      line_items: [{ price: getPriceIdForPlan(plan), quantity: 1 }],
      subscription_data: {
        metadata: {
          userId: user.id,
          plan,
        },
      },
      success_url: `${appUrl}/settings?success=true&checkout_session_id={CHECKOUT_SESSION_ID}`,
      cancel_url: `${appUrl}/settings`,
    });

    if (!checkoutSession.url) {
      console.error("stripe.checkout.session_missing_url", { userId: user.id, stripeCustomerId, sessionId: checkoutSession.id });
      return Response.json({ error: "Failed to start checkout" }, { status: 500 });
    }

    return NextResponse.redirect(checkoutSession.url, { status: 303 });
  } catch (error) {
    console.error("stripe.checkout.session_create_failed", { userId: user.id, stripeCustomerId, error });
    return Response.json({ error: "Failed to start checkout" }, { status: 500 });
  }
}

import { eq } from "drizzle-orm";

import { validateSession } from "../../../../lib/auth/session";
import { db } from "../../../../lib/db/client";
import { users } from "../../../../lib/db/schema";
import { getPlanForPriceId } from "../../../../lib/stripe/constants";
import { getStripe } from "../../../../lib/stripe/client";

type ReconcileBody = {
  checkout_session_id?: unknown;
};

function getExpandedId(value: unknown): string | null {
  if (typeof value === "string" && value.length > 0) return value;
  if (value && typeof value === "object" && "id" in value && typeof (value as { id?: unknown }).id === "string") {
    const id = (value as { id: string }).id;
    return id.length > 0 ? id : null;
  }
  return null;
}

function getUnixSecondsDate(value: unknown): Date | null {
  let seconds: number | null = null;

  if (typeof value === "number" && Number.isFinite(value)) {
    seconds = Math.floor(value);
  } else if (typeof value === "string" && value.trim().length > 0) {
    const parsed = Number(value);
    if (Number.isFinite(parsed)) {
      seconds = Math.floor(parsed);
    }
  } else if (typeof value === "bigint") {
    const parsed = Number(value);
    if (Number.isSafeInteger(parsed)) {
      seconds = parsed;
    }
  }

  if (seconds === null) return null;
  return new Date(seconds * 1000);
}

export async function POST(request: Request): Promise<Response> {
  const session = await validateSession(request);
  if (!session) {
    return Response.json({ error: "Unauthorized" }, { status: 401 });
  }

  let json: unknown;
  try {
    json = await request.json();
  } catch {
    return Response.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  const body = json as ReconcileBody;
  const checkoutSessionId = typeof body.checkout_session_id === "string" ? body.checkout_session_id : null;
  if (!checkoutSessionId) {
    return Response.json({ error: "Missing checkout_session_id" }, { status: 400 });
  }

  const userRows = await db
    .select({ id: users.id, plan: users.plan, stripeCustomerId: users.stripeCustomerId })
    .from(users)
    .where(eq(users.id, session.userId));
  const user = userRows[0];
  if (!user) {
    return Response.json({ error: "User not found" }, { status: 404 });
  }

  const stripe = getStripe();

  let checkoutSession: any;
  try {
    checkoutSession = await stripe.checkout.sessions.retrieve(checkoutSessionId, {
      expand: ["subscription", "customer"],
    });
  } catch (error) {
    console.error("stripe.reconcile.checkout_session_retrieve_failed", { checkoutSessionId, error });
    return Response.json({ error: "Invalid checkout_session_id" }, { status: 400 });
  }

  const customerId = getExpandedId(checkoutSession?.customer);
  const subscription = checkoutSession?.subscription;
  const subscriptionId = getExpandedId(subscription);

  const belongsToCustomer = !!(customerId && user.stripeCustomerId && customerId === user.stripeCustomerId);
  const belongsToUserMetadata = subscription?.metadata?.userId === user.id;
  if (!belongsToCustomer && !belongsToUserMetadata) {
    return Response.json({ error: "Forbidden" }, { status: 403 });
  }

  if (!subscriptionId || !subscription || typeof subscription !== "object") {
    return Response.json({ error: "Checkout session missing subscription" }, { status: 400 });
  }

  const priceId = subscription?.items?.data?.[0]?.price?.id;
  const mappedPlan = typeof priceId === "string" ? getPlanForPriceId(priceId) : null;

  const newPlan = mappedPlan ?? user.plan;

  const cancelAtDate = getUnixSecondsDate(subscription.cancel_at);
  const currentPeriodEndDate = getUnixSecondsDate(subscription.current_period_end) ?? cancelAtDate;
  const hasScheduledCancellation = !!cancelAtDate && (subscription.canceled_at === null || subscription.canceled_at === undefined);
  const cancelAtPeriodEnd =
    hasScheduledCancellation || typeof subscription.cancel_at_period_end !== "boolean" ? hasScheduledCancellation : subscription.cancel_at_period_end;

  const updatedRows = await db
    .update(users)
    .set({
      plan: newPlan,
      stripeSubscriptionId: subscriptionId,
      stripeSubscriptionStatus: typeof subscription.status === "string" ? subscription.status : null,
      stripePriceId: typeof priceId === "string" ? priceId : null,
      stripeCurrentPeriodEnd: currentPeriodEndDate,
      stripeCancelAtPeriodEnd: cancelAtPeriodEnd,
    })
    .where(eq(users.id, user.id))
    .returning();

  const updated = updatedRows[0];
  if (!updated) {
    return Response.json({ error: "Failed to update subscription" }, { status: 500 });
  }

  return Response.json({ plan: updated.plan, stripeSubscriptionId: updated.stripeSubscriptionId });
}

import { eq } from "drizzle-orm";

import { db } from "../../../../lib/db/client";
import { users } from "../../../../lib/db/schema";
import { readRequiredEnv } from "../../../../lib/env/read-required-env";
import { getPlanForPriceId } from "../../../../lib/stripe/constants";
import { getStripe } from "../../../../lib/stripe/client";

type UserForStripeWebhook = {
  id: string;
  plan: string;
  stripeCustomerId: string | null;
  stripeLastWebhookEventId: string | null;
  stripeLastWebhookEventCreated: bigint | null;
};

function toUnixSecondsBigint(value: unknown): bigint | null {
  if (typeof value === "number" && Number.isFinite(value)) return BigInt(Math.floor(value));
  if (typeof value === "string" && value.trim().length > 0) {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? BigInt(Math.floor(parsed)) : null;
  }
  if (typeof value === "bigint") return value;
  return null;
}

function toUnixSecondsDate(value: unknown): Date | null {
  if (typeof value === "number" && Number.isFinite(value)) return new Date(Math.floor(value) * 1000);
  if (typeof value === "string" && value.trim().length > 0) {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? new Date(Math.floor(parsed) * 1000) : null;
  }
  if (typeof value === "bigint") {
    const parsed = Number(value);
    return Number.isSafeInteger(parsed) ? new Date(parsed * 1000) : null;
  }
  return null;
}

function getExpandedId(value: unknown): string | null {
  if (typeof value === "string" && value.length > 0) return value;
  if (value && typeof value === "object" && "id" in value && typeof (value as { id?: unknown }).id === "string") {
    const id = (value as { id: string }).id;
    return id.length > 0 ? id : null;
  }
  return null;
}

function shouldIgnoreEvent(user: UserForStripeWebhook, eventId: string, eventCreated: bigint | null): boolean {
  if (user.stripeLastWebhookEventId && user.stripeLastWebhookEventId === eventId) return true;
  if (eventCreated && user.stripeLastWebhookEventCreated && eventCreated < user.stripeLastWebhookEventCreated) return true;
  return false;
}

async function findUserByStripeCustomerId(customerId: string): Promise<UserForStripeWebhook | null> {
  const rows = await db
    .select({
      id: users.id,
      plan: users.plan,
      stripeCustomerId: users.stripeCustomerId,
      stripeLastWebhookEventId: users.stripeLastWebhookEventId,
      stripeLastWebhookEventCreated: users.stripeLastWebhookEventCreated,
    })
    .from(users)
    .where(eq(users.stripeCustomerId, customerId));

  return rows[0] ?? null;
}

export async function POST(request: Request): Promise<Response> {
  const signatureHeader = request.headers.get("stripe-signature");
  if (!signatureHeader) {
    return new Response("Missing Stripe signature", { status: 400 });
  }

  const secret = readRequiredEnv("STRIPE_WEBHOOK_SECRET");
  const body = await request.text();

  const stripe = getStripe();

  let event: any;
  try {
    event = stripe.webhooks.constructEvent(body, signatureHeader, secret);
  } catch (error) {
    console.error("stripe.webhook.signature_verification_failed", { error });
    return new Response("Invalid Stripe signature", { status: 400 });
  }

  const eventId = typeof event?.id === "string" ? event.id : "unknown";
  const eventType = typeof event?.type === "string" ? event.type : "unknown";
  const eventCreated = toUnixSecondsBigint(event?.created);

  const object = event?.data?.object;

  const customerId =
    typeof object?.customer === "string"
      ? object.customer
      : typeof object?.customer?.id === "string"
        ? object.customer.id
        : null;

  const subscriptionId =
    typeof object?.subscription === "string"
      ? object.subscription
      : typeof object?.id === "string" && (object?.object === "subscription" || eventType.startsWith("customer.subscription."))
        ? object.id
        : null;

  const priceId = object?.items?.data?.[0]?.price?.id;

  if (!customerId) {
    console.error("stripe.webhook.missing_customer", { eventId, eventType, subscriptionId, priceId });
    return Response.json({ ok: true }, { status: 200 });
  }

  const user = await findUserByStripeCustomerId(customerId);
  if (!user) {
    console.error("stripe.webhook.user_not_found", { eventId, eventType, customerId, subscriptionId, priceId });
    return Response.json({ ok: true }, { status: 200 });
  }

  if (shouldIgnoreEvent(user, eventId, eventCreated)) {
    return Response.json({ ok: true, ignored: true }, { status: 200 });
  }

  try {
    switch (eventType) {
      case "checkout.session.completed": {
        const checkoutSubscriptionId = getExpandedId(object?.subscription);
        if (!checkoutSubscriptionId) {
          console.info("stripe.webhook.checkout_session_completed.no_subscription", { eventId, customerId });
          break;
        }

        await db
          .update(users)
          .set({
            stripeSubscriptionId: checkoutSubscriptionId,
            stripeLastWebhookEventId: eventId,
            stripeLastWebhookEventCreated: eventCreated,
          })
          .where(eq(users.id, user.id));

        break;
      }

      case "customer.subscription.updated": {
        const mappedPlan = typeof priceId === "string" ? getPlanForPriceId(priceId) : null;
        if (!mappedPlan && typeof priceId === "string") {
          console.error("stripe.webhook.unknown_price_id", { eventId, eventType, customerId, subscriptionId, priceId, userId: user.id });
        }

        const cancelAtDate = toUnixSecondsDate(object?.cancel_at);
        const currentPeriodEndDate = toUnixSecondsDate(object?.current_period_end) ?? cancelAtDate;
        const hasScheduledCancellation = !!cancelAtDate && (object?.canceled_at === null || object?.canceled_at === undefined);
        const cancelAtPeriodEnd =
          hasScheduledCancellation || typeof object?.cancel_at_period_end !== "boolean" ? hasScheduledCancellation : object.cancel_at_period_end;

        const setValues: Record<string, unknown> = {
          stripeSubscriptionId: subscriptionId,
          stripeSubscriptionStatus: typeof object?.status === "string" ? object.status : null,
          stripePriceId: typeof priceId === "string" ? priceId : null,
          stripeCurrentPeriodEnd: currentPeriodEndDate,
          stripeCancelAtPeriodEnd: cancelAtPeriodEnd,
          stripeLastWebhookEventId: eventId,
          stripeLastWebhookEventCreated: eventCreated,
        };

        if (mappedPlan) {
          setValues.plan = mappedPlan;
        }

        await db.update(users).set(setValues).where(eq(users.id, user.id));
        break;
      }

      case "customer.subscription.deleted": {
        const status = typeof object?.status === "string" ? object.status : null;
        await db
          .update(users)
          .set({
            plan: "free",
            stripeSubscriptionStatus: status,
            stripeLastWebhookEventId: eventId,
            stripeLastWebhookEventCreated: eventCreated,
          })
          .where(eq(users.id, user.id));
        break;
      }

      case "invoice.payment_failed": {
        await db
          .update(users)
          .set({
            stripeSubscriptionId: subscriptionId,
            stripeSubscriptionStatus: "past_due",
            stripeLastWebhookEventId: eventId,
            stripeLastWebhookEventCreated: eventCreated,
          })
          .where(eq(users.id, user.id));
        break;
      }

      default: {
        console.info("stripe.webhook.unhandled_event", { eventId, eventType, customerId, subscriptionId, priceId });
        break;
      }
    }
  } catch (error) {
    console.error("stripe.webhook.processing_failed", { eventId, eventType, customerId, subscriptionId, priceId, error });
    return new Response("Webhook handler error", { status: 500 });
  }

  return Response.json({ ok: true }, { status: 200 });
}

