    };
  }

  const maxSteps = params.maxSteps ?? 5;
  if (!Number.isInteger(maxSteps) || maxSteps < 1 || maxSteps > 10) {
    return {
      status: 'invalid_steps',
      summary: 'Max steps must be an integer from 1 to 10.',
    };
