      dashboardUrls: project.dashboardUrls,
      provenance: createAnalyticsProvenance({
        projectName: project.displayName,
        tool: 'get_paths_to_event',
        semantics: 'paths_to_event',
        dataWindow,
        generatedAt: params.now,
