import { updateProjectStatusForPullRequestClosed } from "../../db/queries/projects";

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

export async function handlePullRequestWebhook(payload: unknown): Promise<void> {
  if (!isRecord(payload)) return;
  const action = payload.action;
  if (action !== "closed") return;

  const pullRequest = payload.pull_request;
  const repository = payload.repository;
  if (!isRecord(pullRequest) || !isRecord(repository)) return;

  const prNumber = pullRequest.number;
  const merged = pullRequest.merged;
  const repoId = repository.id;

  if (typeof prNumber !== "number" || !Number.isInteger(prNumber)) return;
  if (typeof merged !== "boolean") return;
  if (typeof repoId !== "number" || !Number.isFinite(repoId)) return;

  const status = merged ? "active" : "pr_closed";
  await updateProjectStatusForPullRequestClosed({ repoId: BigInt(repoId), prNumber, status });
}

import { mcpRepoContextSchema, type McpRepoContextInput } from "../tools/schemas";

const MAX_FILE_BYTES = 64 * 1024;
const MAX_TOTAL_BYTES = 256 * 1024;

const LOCKFILE_NAMES = new Set(["package-lock.json", "pnpm-lock.yaml", "yarn.lock", "bun.lock", "bun.lockb"]);
const CONFIG_FILE_NAMES = new Set([
  "tsconfig.json",
  "jsconfig.json",
  "next.config.js",
  "next.config.mjs",
  "next.config.cjs",
  "next.config.ts",
]);

export type RepoContextValidationReason =
  | "invalid_schema"
  | "unsupported_framework"
  | "missing_package_json"
  | "missing_entrypoint"
  | "disallowed_file"
  | "request_too_large";

export type ValidatedRepoContext = {
  repo: McpRepoContextInput["repo"] & {
    workspaceRoot: string;
    appRoot: string;
    dependencyTarget: string;
  };
  framework: McpRepoContextInput["framework"] & {
    entrypoint: string;
  };
  files: Record<string, string>;
  packageJsonPath: string;
  entrypointPath: string;
  totalBytes: number;
};

export type RepoContextValidationResult =
  | { ok: true; context: ValidatedRepoContext }
  | { ok: false; reason: RepoContextValidationReason; message: string; path?: string };

function byteLength(value: string): number {
  return Buffer.byteLength(value, "utf8");
}

function pathBasename(path: string): string {
  return path.split("/").at(-1) ?? path;
}

function hasUrlScheme(path: string): boolean {
  return /^[a-z][a-z0-9+.-]*:/i.test(path);
}

function decodePathSegment(segment: string): string | null {
  let decoded = segment;
  for (let i = 0; i < 2; i += 1) {
    try {
      decoded = decodeURIComponent(decoded);
    } catch {
      return null;
    }
  }
  return decoded;
}

function normalizeRelativePath(path: string, options: { allowDot?: boolean } = {}): string | null {
  const trimmed = path.trim().replace(/\/+$/, "");
  if (options.allowDot && trimmed === ".") return ".";
  if (!trimmed || trimmed === ".") return null;
  if (trimmed.startsWith("/") || trimmed.startsWith("//")) return null;
  if (trimmed.startsWith("~")) return null;
  if (trimmed.includes("\\")) return null;
  if (/^[a-z]:[\\/]/i.test(trimmed)) return null;
  if (hasUrlScheme(trimmed)) return null;

  const segments = trimmed.split("/");
  for (const segment of segments) {
    if (!segment) return null;
    const decoded = decodePathSegment(segment);
    if (!decoded || decoded === "." || decoded === "..") return null;
  }

  return segments.join("/");
}

function joinAppPath(appRoot: string, path: string): string {
  return appRoot === "." ? path : `${appRoot}/${path}`;
}

function isEntrypointForFramework(kind: McpRepoContextInput["framework"]["kind"], path: string): boolean {
  if (!/\.(tsx|jsx)$/.test(path)) return false;
  if (kind === "nextjs-app-router") return /(^|\/)(src\/)?app\/layout\.(tsx|jsx)$/.test(path);
  if (kind === "nextjs-pages-router") return /(^|\/)(src\/)?pages\/_app\.(tsx|jsx)$/.test(path);
  return false;
}

export function isNextEntrypointPath(path: string): boolean {
  return /(^|\/)(src\/)?app\/layout\.(tsx|jsx)$/.test(path) || /(^|\/)(src\/)?pages\/_app\.(tsx|jsx)$/.test(path);
}

function isTallyWrapperPath(path: string): boolean {
  return /(^|\/)(src\/)?components\/tally-analytics\.(tsx|jsx)$/.test(path);
}

function isSensitiveOrUnsupportedFile(path: string): boolean {
  const basename = pathBasename(path).toLowerCase();
  if (basename === ".env" || basename.startsWith(".env.")) return true;
  if (LOCKFILE_NAMES.has(basename)) return true;
  if (basename === "id_rsa" || basename === "id_dsa" || basename === "id_ed25519") return true;
  if (/\.(pem|key|p12|pfx)$/i.test(basename)) return true;
  return /credential|secret|private|token/.test(basename);
}

function containsBinaryContent(content: string): boolean {
  return /[\u0000-\u0008\u000b\u000c\u000e-\u001f]/.test(content);
}

function isAllowedContextPath(path: string, context: { appRoot: string; dependencyTarget: string; entrypoint: string }): boolean {
  if (path === context.dependencyTarget) return true;
  if (path === context.entrypoint) return true;
  if (pathBasename(path) === "package.json") return true;
  if (isNextEntrypointPath(path)) return true;
  if (isTallyWrapperPath(path)) return true;
  if (path === "pnpm-workspace.yaml") return true;

  for (const name of CONFIG_FILE_NAMES) {
    if (path === joinAppPath(context.appRoot, name)) return true;
  }

  return false;
}

function fail(reason: RepoContextValidationReason, message: string, path?: string): RepoContextValidationResult {
  return { ok: false, reason, message, path };
}

export function validateRepoContext(input: unknown): RepoContextValidationResult {
  const parsed = mcpRepoContextSchema.safeParse(input);
  if (!parsed.success) return fail("invalid_schema", "Repo context does not match the MCP input schema");

  const repo = parsed.data.repo;
  const framework = parsed.data.framework;
  const workspaceRoot = normalizeRelativePath(repo.workspaceRoot, { allowDot: true });
  const appRoot = normalizeRelativePath(repo.appRoot, { allowDot: true });
  const dependencyTarget = normalizeRelativePath(repo.dependencyTarget);
  const entrypoint = normalizeRelativePath(framework.entrypoint);

  if (!workspaceRoot) return fail("disallowed_file", "workspaceRoot must be a safe relative path", repo.workspaceRoot);
  if (!appRoot) return fail("disallowed_file", "appRoot must be a safe relative path", repo.appRoot);
  if (!dependencyTarget) return fail("disallowed_file", "dependencyTarget must be a safe relative path", repo.dependencyTarget);
  if (!entrypoint) return fail("disallowed_file", "entrypoint must be a safe relative path", framework.entrypoint);
  if (!dependencyTarget.endsWith("/package.json") && dependencyTarget !== "package.json") {
    return fail("missing_package_json", "dependencyTarget must point to package.json", dependencyTarget);
  }
  if (!isEntrypointForFramework(framework.kind, entrypoint)) {
    return fail("unsupported_framework", "framework.entrypoint is not a supported Next.js TSX/JSX entrypoint", entrypoint);
  }

  const normalizedFiles: Record<string, string> = {};
  let totalBytes = 0;

  for (const [rawPath, rawContent] of Object.entries(parsed.data.files)) {
    const path = normalizeRelativePath(rawPath);
    if (!path) return fail("disallowed_file", "files must use safe relative paths", rawPath);
    if (isSensitiveOrUnsupportedFile(path)) return fail("disallowed_file", "file is not allowed in MCP repo context", path);
    if (!isAllowedContextPath(path, { appRoot, dependencyTarget, entrypoint })) {
      return fail("disallowed_file", "file is outside the MCP repo context allowlist", path);
    }

    const content = rawContent.replace(/\r\n?/g, "\n");
    if (containsBinaryContent(content)) return fail("disallowed_file", "binary file content is not allowed", path);

    const size = byteLength(content);
    if (size > MAX_FILE_BYTES) return fail("request_too_large", "file content exceeds the 64 KB per-file limit", path);

    totalBytes += size;
    if (totalBytes > MAX_TOTAL_BYTES) return fail("request_too_large", "repo context exceeds the 256 KB total limit");
    normalizedFiles[path] = content;
  }

  if (!Object.prototype.hasOwnProperty.call(normalizedFiles, dependencyTarget)) {
    return fail("missing_package_json", "repo context is missing dependencyTarget package.json", dependencyTarget);
  }
  if (!Object.prototype.hasOwnProperty.call(normalizedFiles, entrypoint)) {
    return fail("missing_entrypoint", "repo context is missing framework.entrypoint", entrypoint);
  }

  return {
    ok: true,
    context: {
      repo: {
        ...repo,
        workspaceRoot,
        appRoot,
        dependencyTarget,
      },
      framework: {
        ...framework,
        entrypoint,
      },
      files: normalizedFiles,
      packageJsonPath: dependencyTarget,
      entrypointPath: entrypoint,
      totalBytes,
    },
  };
}

import { validateRepoContext } from "./context";
import { detectNextInstallTarget, type NextInstallTarget } from "./detect";
import { addTallySdkDependency, TALLY_SDK_PACKAGE } from "./package-json";
import { createOrReuseInstallProject } from "./project-reuse";
import {
  insertTallyIntoEntrypoint,
  renderTallyWrapper,
  resolveTallyWrapperPaths,
  TALLY_ANALYTICS_COMPONENT,
  TALLY_ANALYTICS_HOOK,
} from "./templates";
import { unifiedDiff } from "./unified-diff";

export type PrepareNextjsInstallPatchParams = {
  userId: string;
  input: unknown;
};

export type PrepareNextjsInstallPatchResult =
  | {
      status: "ready";
      projectId: string;
      dashboardUrl: string;
      projectCreated: boolean;
      target: NextInstallTarget;
      patchFormat: "unified_diff_v1";
      unifiedDiff: string;
      filesChanged: string[];
      packageInstallCommand: string;
      verification: string[];
    }
  | {
      status: "unsupported";
      reason:
        | "unsupported_framework"
        | "ambiguous_app_root"
        | "multiple_matching_projects"
        | "disallowed_file"
        | "request_too_large"
        | "patch_not_confident"
        | "existing_integration_conflict";
      message?: string;
    }
  | { status: "needs_context"; missingFiles: string[] }
  | { status: "already_installed"; projectId: string; dashboardUrl: string; unifiedDiff: "" };

function packageInstallCommand(packageManager: NextInstallTarget["packageManager"]): string {
  if (packageManager === "pnpm") return "pnpm install";
  if (packageManager === "yarn") return "yarn install";
  if (packageManager === "bun") return "bun install";
  return "npm install";
}

function verificationChecklist(): string[] {
  return [
    "Apply the unified diff with git apply --check before git apply.",
    "Run the package install command.",
    "Run the app's typecheck/build command.",
    "Deploy the app.",
    "Visit one or two pages.",
    "Open the dashboard URL and confirm events appear.",
  ];
}

function hasTallySdkDependency(packageJsonContent: string): boolean {
  try {
    const parsed = JSON.parse(packageJsonContent) as { dependencies?: Record<string, string> };
    return typeof parsed.dependencies?.[TALLY_SDK_PACKAGE] === "string";
  } catch {
    return false;
  }
}

function isAlreadyInstalled(params: {
  packageJsonContent: string;
  wrapperContent: string | undefined;
  entrypointContent: string;
  projectId: string;
  router: NextInstallTarget["router"];
}): boolean {
  const expectedSymbol = params.router === "app" ? TALLY_ANALYTICS_COMPONENT : TALLY_ANALYTICS_HOOK;
  return (
    hasTallySdkDependency(params.packageJsonContent) &&
    typeof params.wrapperContent === "string" &&
    params.wrapperContent.includes(`projectId: '${params.projectId}'`) &&
    params.entrypointContent.includes(expectedSymbol)
  );
}

function hasExistingTallyIntegration(params: {
  packageJsonContent: string;
  wrapperContent: string | undefined;
  entrypointContent: string;
}): boolean {
  return (
    hasTallySdkDependency(params.packageJsonContent) ||
    typeof params.wrapperContent === "string" ||
    params.entrypointContent.includes(TALLY_ANALYTICS_COMPONENT) ||
    params.entrypointContent.includes(TALLY_ANALYTICS_HOOK) ||
    params.entrypointContent.includes("@tally-analytics/sdk")
  );
}

export async function prepareNextjsInstallPatch(
  params: PrepareNextjsInstallPatchParams,
): Promise<PrepareNextjsInstallPatchResult> {
  const validated = validateRepoContext(params.input);
  if (!validated.ok) {
    if (validated.reason === "missing_package_json" && validated.path) {
      return { status: "needs_context", missingFiles: [validated.path] };
    }
    if (validated.reason === "missing_entrypoint" && validated.path) {
      return { status: "needs_context", missingFiles: [validated.path] };
    }
    if (validated.reason === "request_too_large") {
      return { status: "unsupported", reason: "request_too_large", message: validated.message };
    }
    return { status: "unsupported", reason: "disallowed_file", message: validated.message };
  }

  const detection = detectNextInstallTarget(validated.context);
  if (detection.status === "unsupported") {
    if (detection.reason === "missing_package_json") {
      return { status: "needs_context", missingFiles: [validated.context.packageJsonPath] };
    }
    if (detection.reason === "missing_entrypoint") {
      return { status: "needs_context", missingFiles: [validated.context.entrypointPath] };
    }
    return { status: "unsupported", reason: detection.reason, message: detection.message };
  }

  const project = await createOrReuseInstallProject({
    userId: params.userId,
    context: validated.context,
    target: detection.target,
  });

  if (project.status === "unsupported") {
    return { status: "unsupported", reason: project.reason };
  }

  const packageJsonContent = validated.context.files[detection.target.packageJsonPath] ?? "";
  const entrypointContent = validated.context.files[detection.target.entrypointPath] ?? "";
  const paths = resolveTallyWrapperPaths(detection.target);
  const wrapperContent = validated.context.files[paths.wrapperFilePath];

  if (
    isAlreadyInstalled({
      packageJsonContent,
      wrapperContent,
      entrypointContent,
      projectId: project.projectId,
      router: detection.target.router,
    })
  ) {
    return { status: "already_installed", projectId: project.projectId, dashboardUrl: project.dashboardUrl, unifiedDiff: "" };
  }

  if (hasExistingTallyIntegration({ packageJsonContent, wrapperContent, entrypointContent })) {
    return {
      status: "unsupported",
      reason: "existing_integration_conflict",
      message: "Existing Tally integration is present but does not match the current project",
    };
  }

  const packageEdit = addTallySdkDependency(packageJsonContent);
  const renderedWrapper = renderTallyWrapper({ router: detection.target.router, projectId: project.projectId });
  const updatedEntrypoint = insertTallyIntoEntrypoint({
    target: detection.target,
    content: entrypointContent,
    wrapperImportPath: paths.wrapperImportPath,
  });
  const filesChanged = [detection.target.packageJsonPath, paths.wrapperFilePath, detection.target.entrypointPath];
  const patch = unifiedDiff([
    { path: detection.target.packageJsonPath, oldContent: packageJsonContent, newContent: packageEdit.content },
    { path: paths.wrapperFilePath, oldContent: null, newContent: renderedWrapper },
    { path: detection.target.entrypointPath, oldContent: entrypointContent, newContent: updatedEntrypoint },
  ]);

  return {
    status: "ready",
    projectId: project.projectId,
    dashboardUrl: project.dashboardUrl,
    projectCreated: project.created,
    target: detection.target,
    patchFormat: "unified_diff_v1",
    unifiedDiff: patch,
    filesChanged,
    packageInstallCommand: packageInstallCommand(detection.target.packageManager),
    verification: verificationChecklist(),
  };
}

